PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?date WHERE {
  ?match wdt:P2072 wd:Q266613 ;
         wdt:P585 ?date ;
         wdt:P20/wdt:P176 wd:Q19837 .
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?date WHERE {
  ?match wdt:P2072 wd:Q266613 ;
         wdt:P585 ?date ;
         wdt:P361 ?event .
  ?event wdt:P179 wd:Q19837 .
}
ORDER BY ?date
LIMIT 1

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?date WHERE {
  ?match wdt:P31 ?event ;
         wdt:P701 wd:Q266613 .
  ?event wdt:P179 wd:Q19837 .
  ?match wdt:P585 ?date .
}
ORDER BY ?date
LIMIT 1
